import React, { useState } from 'react';
import './WorkshopsPage.css';

export default function WorkshopsPage() {
  const [selectedCategory, setSelectedCategory] = useState('All');

  const workshops = [
    {
      id: 1,
      title: 'Drone Dasar',
      category: 'Semester 1',
      level: 'Beginner',
      capacity: 30,
      image: '/1.jpg',
      description: 'Belajar dasar drone dan kontrol sederhana.',
      instructor: 'Dr. James Lee',
      startDate: 'Mar 15, 2025',
    },
    {
      id: 2,
      title: 'Drone Lanjutan',
      category: 'Semester 2',
      level: 'Advanced',
      capacity: 20,
      image: '/1.jpg',
      description: 'Navigasi drone otomatis & AI.',
      instructor: 'Engineer Mike',
      startDate: 'Mar 20, 2025',
    },
    {
      id: 3,
      title: 'Microcontroller Agro',
      category: 'Semester 3',
      level: 'Beginner',
      capacity: 25,
      image: '/1.jpg',
      description: 'Kontrol sistem pertanian otomatis.',
      instructor: 'Prof. Emma',
      startDate: 'Mar 10, 2025',
    },
    {
      id: 4,
      title: 'Raspberry Pi Robot',
      category: 'Semester 4',
      level: 'Advanced',
      capacity: 15,
      image: '/1.jpg',
      description: 'Robot berbasis Raspberry Pi.',
      instructor: 'Prof. Emma',
      startDate: 'Mar 10, 2025',
    },
    {
      id: 5,
      title: 'Raspberry Pi Robot',
      category: 'Semester 5',
      level: 'Advanced',
      capacity: 15,
      image: '/1.jpg',
      description: 'Robot berbasis Raspberry Pi.',
      instructor: 'Prof. Emma',
      startDate: 'Mar 10, 2025',
    },
        {
      id: 6,
      title: 'Raspberry Pi Robot',
      category: 'Semester 6',
      level: 'Advanced',
      capacity: 15,
      image: '/1.jpg',
      description: 'Robot berbasis Raspberry Pi.',
      instructor: 'Prof. Emma',
      startDate: 'Mar 10, 2025',
    },
  ];

  const categories = ['All', 'Semester 1', 'Semester 2', 'Semester 3', 'Semester 4', 'Semester 5', 'Semester 6'];

  const filteredWorkshops =
    selectedCategory === 'All'
      ? workshops
      : workshops.filter(w => w.category === selectedCategory);

  return (
    <div className="page">

      {/* HEADER */}
      <section className="page-header-ws">
        <div className="container">
          <h1>Workshops MURO</h1>
          <p>Level up your skills with our hands-on programs</p>
        </div>
      </section>

      {/* CONTENT */}
      <section className="workshops-section">
        <div className="container">

          {/* FILTER */}
          <div className="category-filter">
            {categories.map(category => (
              <button
                key={category}
                className={`category-btn ${selectedCategory === category ? 'active' : ''}`}
                onClick={() => setSelectedCategory(category)}
              >
                {category}
              </button>
            ))}
          </div>

          {/* GRID */}
          <div className="workshops-grid">
            {filteredWorkshops.map(workshop => (
              <div key={workshop.id} className="workshop-card">


                {/* IMAGE */}
                <div className="image-box">
                  <img src={workshop.image} alt={workshop.title} className="workshop-image" />
                  <span className={`badge-level ${workshop.level.toLowerCase()}`}>
                    {workshop.level}
                  </span>
                </div>

                {/* CONTENT */}
                <h3 className="workshop-title">{workshop.title}</h3>
                <p className="workshop-description">{workshop.description}</p>

                <div className="workshop-meta">
                  <span>👨‍🏫 {workshop.instructor}</span>
                  <span>📅 {workshop.startDate}</span>
                  <span>👥 {workshop.capacity} peserta</span>
                </div>

                {/* BUTTON */}
                <div className="btn-group">
                  <button className="btn-outline">Pengajuan Blanko</button>
                  <button className="btn-primary">Konfirmasi Pembayaran</button>
                </div>

              </div>
            ))}
          </div>
        </div>
      </section>
    </div>
  );
}
